"use client";

import { useTranslations } from "next-intl";

import { BookIllustration } from "@/components/ui/BookIllustration";
import { Link } from "@/i18n/navigation";

type PromoCardProps =
  | { variant: "book" }
  | { variant: "community"; ctaHref: string };

const variantConfig = {
  book: {
    bg: "bg-tan",
    paddingClass: "px-10 py-10 md:px-12",
    headingClass:
      "font-display text-2xl font-semibold leading-none text-ink",
  },
  community: {
    bg: "bg-lavender",
    paddingClass: "px-10 py-10 md:px-12",
    headingClass:
      "font-display text-2xl font-semibold leading-none text-ink max-w-[180px]",
  },
} as const;

const promoSurfaceClass = "promo-card-light-surface";

